    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override void OnParametersSet() => _loading = false;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (HasMore && !_observerAttached)
        {
            await AttachObserverAsync();
        }
        else if (!HasMore && _observerAttached)
        {
            await DetachObserverAsync();
        }
    }

