        _dotNetRef = DotNetObjectReference.Create((InfiniteScrollListBase)this);
        await _interop.InitializeAsync(_sentinelRef, _dotNetRef);
        _observerAttached = true;
    }

    private async Task DetachObserverAsync()
    {
        if (_interop is not null)
        {
            await _interop.DisposeAsync();
            _interop = null;
        }
        _observerAttached = false;
    }

    public override async Task OnSentinelVisible()
    {
        if (_loading || !HasMore) return;

        _loading = true;
        await InvokeAsync(StateHasChanged);
        await OnLoadMore.InvokeAsync();
    }

    async ValueTask IAsyncDisposable.DisposeAsync()
    {
        await DetachObserverAsync();
        _dotNetRef?.Dispose();
    }
}

